const blockTitlesRaw = $('Reclaim Block Titles').first().json.reclaimBlockTitles || '';
const blockPatterns = blockTitlesRaw.split(',').map(s => s.trim().toLowerCase()).filter(Boolean);

const events = $input.all().map(item => {
  const e = item.json;
  const start = e.start?.dateTime || e.start?.date;
  const isAllDay = !e.start?.dateTime;
  const title = e.summary || '(No title)';
  const titleLower = title.toLowerCase().trim();

  // Work block = title matches one of the configured Reclaim block patterns
  // Edit the "Reclaim Block Titles" node to add/remove patterns (comma-separated)
  const isWorkBlock = blockPatterns.some(p => titleLower.startsWith(p) || titleLower === p);

  // Metadata flag — did Reclaim touch this event?
  const desc = (e.description || '').toLowerCase();
  const id = (e.id || '').toLowerCase();
  const isReclaim = id.startsWith('reclaim0') ||
    desc.includes('reclaim.ai') || desc.includes('reclaim</a>');

  const attendees = (e.attendees || [])
    .filter(a => a.email !== 'alex@ahbadvisors.com')
    .map(a => ({
      email: a.email,
      name: a.displayName || a.email.split('@')[0],
      responseStatus: a.responseStatus
    }));

  return {
    json: {
      eventId: e.id,
      title,
      startTime: start,
      endTime: e.end?.dateTime || e.end?.date,
      isAllDay,
      isReclaim,
      isWorkBlock,
      location: e.location || null,
      attendees,
      attendeeCount: attendees.length,
      calendarLink: e.htmlLink,
      description: e.description || ''
    }
  };
});

return events.length > 0 ? events : [{ json: { events: [], message: 'No events today' } }];

// Native ClickUp node returns each task as a separate item
const items = $input.all();
const agendas = items.map(item => {
  const t = item.json;
  return {
    taskId: t.id,
    name: t.name,
    description: (t.description || '').substring(0, 500),
    dueDate: t.due_date,
    url: t.url,
    tags: (t.tags || []).map(tag => tag.name)
  };
}).filter(a => a.taskId);

return [{ json: { agendas } }];

const allTasks = $input.first().json.tasks || [];
// Exclude meeting agenda tasks — already shown in calendar section
const AGENDA_LIST_ID = '901107582941';
const tasks = allTasks.filter(t => t.list?.id !== AGENDA_LIST_ID);
const now = Date.now();
const todayStart = new Date(); todayStart.setHours(0, 0, 0, 0);
const todayEnd = new Date(); todayEnd.setHours(23, 59, 59, 999);
const todayEndMs = todayEnd.getTime();
const threeDaysMs = todayEndMs + 3 * 86400000;

const categorized = {
  overdue: [],
  dueToday: [],
  upcoming: [],
  noDueDate: []
};

for (const t of tasks) {
  const due = t.due_date ? parseInt(t.due_date) : null;
  const daysOverdue = due ? Math.floor((now - due) / 86400000) : 0;

  const task = {
    taskId: t.id,
    name: t.name,
    status: t.status?.status || 'unknown',
    dueDate: t.due_date,
    dueDateFormatted: due ? new Date(due).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) : 'No date',
    daysOverdue: daysOverdue > 0 ? daysOverdue : 0,
    priority: t.priority?.priority || 'normal',
    list: t.list?.name || 'Unknown',
    url: t.url,
    tags: (t.tags || []).map(tag => tag.name)
  };

  if (!due) {
    categorized.noDueDate.push(task);
  } else if (due < todayStart.getTime()) {
    categorized.overdue.push(task);
  } else if (due <= todayEndMs) {
    categorized.dueToday.push(task);
  } else if (due <= threeDaysMs) {
    categorized.upcoming.push(task);
  }
  // Tasks due >3 days out are excluded from the brief
}

return [{ json: { myTasks: categorized } }];

// Native ClickUp node returns each task as a separate item
const items = $input.all();
const current = items[0]?.json;
if (!current || !current.id) return [{ json: { weeklyGoals: null, message: 'No weekly goals task found' } }];

const checklists = current.checklists || [];
let totalItems = 0;
let completedItems = 0;
const goals = [];

for (const cl of checklists) {
  for (const item of (cl.items || [])) {
    totalItems++;
    if (item.resolved) completedItems++;
    goals.push({
      name: item.name,
      resolved: item.resolved,
      section: cl.name
    });
  }
}

return [{
  json: {
    weeklyGoals: {
      taskId: current.id,
      taskName: current.name,
      url: current.url,
      totalItems,
      completedItems,
      completionPct: totalItems > 0 ? Math.round((completedItems / totalItems) * 100) : 0,
      goals
    }
  }
}];

const tasks = $input.first().json.tasks || [];
return [{
  json: {
    kendraTasks: tasks.map(t => ({
      taskId: t.id,
      name: t.name,
      status: t.status?.status || 'unknown',
      dueDate: t.due_date,
      list: t.list?.name || 'Unknown',
      url: t.url
    }))
  }
}];

const tasks = $input.first().json.tasks || [];
return [{
  json: {
    tylerTasks: tasks.map(t => ({
      taskId: t.id,
      name: t.name,
      status: t.status?.status || 'unknown',
      dueDate: t.due_date,
      list: t.list?.name || 'Unknown',
      url: t.url
    }))
  }
}];

const tasks = $input.first().json.tasks || [];
const excludeIds = ['120026283', '248566802', '87390158'];

const othersTasks = tasks.filter(t => {
  const assignees = (t.assignees || []).map(a => String(a.id));
  return !assignees.some(id => excludeIds.includes(id));
});

return [{
  json: {
    othersTasks: othersTasks.map(t => ({
      taskId: t.id,
      name: t.name,
      assignees: (t.assignees || []).map(a => a.username || a.email || 'User ' + a.id),
      dueDate: t.due_date,
      dueDateFormatted: t.due_date ? new Date(parseInt(t.due_date)).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) : 'No date',
      list: t.list?.name || 'Unknown',
      url: t.url
    }))
  }
}];

// Native Google Drive search returns file objects directly
const item = $input.first().json;
if (!item || !item.id) {
  return [{ json: { notificationDoc: null, message: 'No notification doc found for yesterday' } }];
}
return [{
  json: {
    notificationDoc: {
      name: item.name,
      url: item.webViewLink || 'https://drive.google.com/file/d/' + item.id + '/view',
      id: item.id,
      modifiedTime: item.modifiedTime || item.modifiedDate
    }
  }
}];

// Native Google Drive search returns file objects directly
const item = $input.first().json;
if (!item || !item.id) {
  return [{ json: { newsBriefDoc: null, message: 'No news brief found for today' } }];
}
return [{
  json: {
    newsBriefDoc: {
      name: item.name,
      url: item.webViewLink || 'https://drive.google.com/file/d/' + item.id + '/view',
      id: item.id,
      modifiedTime: item.modifiedTime || item.modifiedDate
    }
  }
}];

const needsReply = $('Missive: Needs Reply').all().flatMap(i => i.json.conversations || []);
const todo = $('Missive: To-Do').all().flatMap(i => i.json.conversations || []);
const recent = $('Missive: Recent Open').all().flatMap(i => i.json.conversations || []);

const knownConvoIds = new Set([
  ...needsReply.map(c => c.id),
  ...todo.map(c => c.id)
]);

const possiblyMissed = recent.filter(c => !knownConvoIds.has(c.id));

const formatConvo = (c) => {
  // Missive API: subject is always null, use latest_message_subject
  const subject = c.latest_message_subject || c.subject || '(no subject)';
  // From: use external_authors (people outside your org)
  const extAuthors = c.external_authors || c.authors || [];
  const from = extAuthors.length > 0 ? extAuthors[0].name || extAuthors[0].address : 'Unknown';
  const fromEmail = extAuthors.length > 0 ? extAuthors[0].address || '' : '';
  // Age: use last_activity_at (unix seconds)
  const lastActivity = c.last_activity_at;
  const ageHours = lastActivity ? Math.floor((Date.now() / 1000 - lastActivity) / 3600) : 0;
  const age = ageHours < 24 ? ageHours + 'h' : Math.floor(ageHours / 24) + 'd';
  // URL: use web_url from API
  const missiveUrl = c.web_url || ('https://mail.missiveapp.com/#inbox/conversations/' + c.id);
  // Labels for context
  const labels = c.shared_label_names || '';
  return { id: c.id, subject, from, fromEmail, age, missiveUrl, labels, receivedAt: lastActivity };
};

return [{
  json: {
    emails: {
      needsReply: needsReply.map(formatConvo),
      todo: todo.map(formatConvo),
      possiblyMissed: possiblyMissed.slice(0, 10).map(formatConvo)
    }
  }
}];

// Parse CLAUDE.md - native GitHub node returns content in .content (base64)
const item = $input.first().json;
let md = '';
if (typeof item.content === 'string' && item.encoding === 'base64') {
  md = Buffer.from(item.content, 'base64').toString('utf-8');
} else if (typeof item.content === 'string') {
  md = item.content;
} else if (typeof item.data === 'string') {
  md = item.data;
} else if (typeof item.body === 'string') {
  md = item.body;
} else {
  md = JSON.stringify(item);
}

function extractSection(text, heading) {
  const pattern = new RegExp('## ' + heading + '\\n([\\s\\S]*?)(?=\\n## |$)');
  const match = text.match(pattern);
  return match ? match[1].trim() : '';
}

const priorities = extractSection(md, 'Current Priorities');
const comms = extractSection(md, 'How to Communicate with Me');
const companies = extractSection(md, 'Companies');

return [{
  json: {
    currentPriorities: priorities,
    communicationStyle: comms,
    companies: companies,
    fullContext: md.substring(0, 8000)
  }
}];

// === DETERMINISTIC ASSEMBLY ===
// Builds the entire daily brief from structured data. All links, tables,
// formatting are deterministic. AI only adds COS Assessment afterward.

// Safe wrappers — if an upstream node hasn't executed or failed, return default
function safeFirst(nodeName, defaultVal = {}) {
  try { return $(nodeName).first()?.json || defaultVal; } catch(e) { return defaultVal; }
}
function safeAll(nodeName) {
  try { return $(nodeName).all().map(i => i.json); } catch(e) { return []; }
}

const calendar = safeAll('Format Calendar');
const agendas = safeFirst('Format Agendas', { agendas: [] }).agendas || [];
const myTasks = safeFirst('Categorize My Tasks', { myTasks: {} }).myTasks || {};
const weeklyGoals = safeFirst('Parse Weekly Goals', { weeklyGoals: null }).weeklyGoals || null;
const kendraTasks = safeFirst('Format Kendra', { kendraTasks: [] }).kendraTasks || [];
const tylerTasks = safeFirst('Format Tyler', { tylerTasks: [] }).tylerTasks || [];
const othersTasks = safeFirst('Filter to Others', { othersTasks: [] }).othersTasks || [];
const notifDoc = safeFirst('Format Notif Doc', { notificationDoc: null }).notificationDoc || null;
const newsDoc = safeFirst('Format News Doc', { newsBriefDoc: null }).newsBriefDoc || null;
const emails = safeFirst('Filter & Format Emails', { emails: {} }).emails || {};

const today = DateTime.now().setZone('America/New_York');
const dateStr = today.toFormat('yyyy-MM-dd');
const dateFmt = today.toFormat('MMMM d, yyyy');
const dayOfWeek = today.toFormat('EEEE');

let md = '# Daily Brief \u2014 ' + dateFmt + ', ' + dayOfWeek + '\n\n';

// --- COS Assessment placeholder (AI inserts here) ---
md += '{{COS_ASSESSMENT}}\n\n';

// --- Current Priorities (from CLAUDE.md via GitHub) ---
const claudeCtx = safeFirst('Parse CLAUDE.md', {});
if (claudeCtx.currentPriorities) {
  md += '## Current Priorities\n\n' + claudeCtx.currentPriorities + '\n\n';
}
if (claudeCtx.communicationStyle) {
  md += '## Communication Style\n\n' + claudeCtx.communicationStyle + '\n\n';
}

// --- News & Notifications ---
md += '## News & Notifications\n';
md += '- **Notification Brief** (yesterday): ' + (notifDoc ? '[' + notifDoc.name + '](' + notifDoc.url + ')' : 'Not available') + '\n';
md += '- **News Brief** (today): ' + (newsDoc ? '[' + newsDoc.name + '](' + newsDoc.url + ')' : 'Not available') + '\n\n';

// --- Calendar ---
md += '## Today\'s Calendar\n\n';
const allEvents = calendar.filter(e => !e.isAllDay && e.title);
const meetings = allEvents.filter(e => !e.isWorkBlock);
const workBlocks = allEvents.filter(e => e.isWorkBlock);
// Deduplicate meetings (Reclaim may duplicate real meetings across calendars)
const seen = new Set();
const dedupedMeetings = [];
for (const m of meetings) {
  const key = m.title + '|' + m.startTime;
  if (!seen.has(key)) {
    seen.add(key);
    dedupedMeetings.push(m);
  }
}

if (dedupedMeetings.length === 0) {
  md += 'Clear calendar \u2014 protect for deep work.\n\n';
} else {
  for (const e of dedupedMeetings) {
    const time = e.startTime ? new Date(e.startTime).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/New_York' }) : 'TBD';
    const endTime = e.endTime ? new Date(e.endTime).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/New_York' }) : '';
    const names = (e.attendees || []).map(a => a.name).join(', ') || '';
    const agenda = agendas.find(a => e.title.toLowerCase().includes(a.name.toLowerCase()) || a.name.toLowerCase().includes(e.title.toLowerCase()));
    const agendaLink = agenda ? ' \u2014 [Agenda](https://app.clickup.com/t/' + agenda.taskId + ')' : '';
    md += '- **' + time + (endTime ? '\u2013' + endTime : '') + '** ' + e.title;
    if (names) md += ' (' + names + ')';
    md += agendaLink + '\n';
  }
  md += '\n';
}

// --- Capacity ---
let meetingMinutes = 0;
for (const e of dedupedMeetings) {
  if (e.startTime && e.endTime) {
    meetingMinutes += (new Date(e.endTime) - new Date(e.startTime)) / 60000;
  }
}
const meetingHours = Math.round(meetingMinutes / 60 * 10) / 10;
const workWindowHours = 10;
const freeHours = Math.max(0, Math.round((workWindowHours - meetingHours) * 10) / 10);

const sortedMeetings = [...dedupedMeetings].filter(e => e.startTime).sort((a, b) => new Date(a.startTime) - new Date(b.startTime));
const workStart = new Date(); workStart.setHours(8, 0, 0, 0);
const workEnd = new Date(); workEnd.setHours(18, 0, 0, 0);
let maxGapMin = 0;
let maxGapStart = workStart;
let maxGapEnd = workEnd;
let prevEnd = workStart;
for (const e of sortedMeetings) {
  const s = new Date(e.startTime);
  const en = new Date(e.endTime);
  const gap = (s - prevEnd) / 60000;
  if (gap > maxGapMin) { maxGapMin = gap; maxGapStart = prevEnd; maxGapEnd = s; }
  if (en > prevEnd) prevEnd = en;
}
const finalGap = (workEnd - prevEnd) / 60000;
if (finalGap > maxGapMin) { maxGapMin = finalGap; maxGapStart = prevEnd; maxGapEnd = workEnd; }
const fmtTime = (d) => d.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/New_York' });

md += '## Today\'s Capacity\n';
md += '- **' + meetings.length + '** meetings (' + meetingHours + ' hours)\n';
md += '- **' + freeHours + '** hours free (8 AM \u2013 6 PM work window)\n';
if (maxGapMin >= 30) {
  md += '- Largest free block: ' + fmtTime(maxGapStart) + ' \u2013 ' + fmtTime(maxGapEnd) + ' (' + Math.round(maxGapMin / 60 * 10) / 10 + ' hours)\n';
}
if (workBlocks.length > 0) {
  md += '- **Work blocks** (Reclaim): ';
  md += workBlocks.map(e => {
    const t = e.startTime ? new Date(e.startTime).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/New_York' }) : '';
    return e.title + (t ? ' (' + t + ')' : '');
  }).join(', ');
  md += '\n';
}
md += '\n';

// --- My Action Items ---
const overdue = myTasks.overdue || [];
const dueToday = myTasks.dueToday || [];
const upcoming = myTasks.upcoming || [];

md += '## My Action Items\n\n';

md += '**Due Today:**\n';
if (dueToday.length === 0) md += 'None\n\n';
else {
  for (const t of dueToday) md += '- ' + t.name + ' \u2014 ' + t.list + ' \u2014 [ClickUp](https://app.clickup.com/t/' + t.taskId + ')\n';
  md += '\n';
}

md += '**Overdue:**\n';
if (overdue.length === 0) md += 'None\n\n';
else {
  for (const t of overdue) md += '- ' + t.name + ' \u2014 ' + t.daysOverdue + ' days overdue \u2014 [ClickUp](https://app.clickup.com/t/' + t.taskId + ')\n';
  md += '\n';
}

md += '**Possible Today** (upcoming 1-3 days):\n';
if (upcoming.length === 0) md += 'None\n\n';
else {
  for (const t of upcoming) md += '- ' + t.name + ' \u2014 due ' + t.dueDateFormatted + ' \u2014 [ClickUp](https://app.clickup.com/t/' + t.taskId + ')\n';
  md += '\n';
}

// --- Weekly Goals ---
md += '## Weekly Goals\n';
if (!weeklyGoals) {
  md += 'No weekly goals set this week.\n\n';
} else {
  md += '**' + weeklyGoals.taskName + '** \u2014 ' + weeklyGoals.completedItems + ' of ' + weeklyGoals.totalItems + ' complete (' + weeklyGoals.completionPct + '%) \u2014 [ClickUp](https://app.clickup.com/t/' + weeklyGoals.taskId + ')\n';
  for (const g of weeklyGoals.goals) md += '- ' + (g.resolved ? '\u2705' : '\u2b1c') + ' ' + g.name + ' \u2014 ' + g.section + '\n';
  md += '\n';
}

// --- Email ---
const nr = emails.needsReply || [];
const td = emails.todo || [];
const pm = emails.possiblyMissed || [];

md += '## Email Attention Needed\n\n';

md += '**Needs Reply:**\n';
if (nr.length === 0) md += 'None\n\n';
else {
  for (const e of nr) md += '- ' + e.subject + ' \u2014 from ' + e.from + ' \u2014 ' + e.age + ' \u2014 [Missive](' + e.missiveUrl + ')\n';
  md += '\n';
}

md += '**To-Do:**\n';
if (td.length === 0) md += 'None\n\n';
else {
  for (const e of td) md += '- ' + e.subject + ' \u2014 [Missive](' + e.missiveUrl + ')\n';
  md += '\n';
}

md += '**Possibly Missed:**\n';
if (pm.length === 0) md += 'None\n\n';
else {
  for (const e of pm) md += '- ' + e.subject + ' \u2014 from ' + e.from + ' \u2014 [Missive](' + e.missiveUrl + ')\n';
  md += '\n';
}

// --- Team ---
md += '## Team Accountability\n\n';

md += '**Kendra (EA):**\n';
if (kendraTasks.length === 0) md += 'No tasks due today.\n\n';
else {
  for (const t of kendraTasks) md += '- [ ] ' + t.name + ' \u2014 ' + t.list + ' \u2014 [ClickUp](https://app.clickup.com/t/' + t.taskId + ')\n';
  md += '\n';
}

md += '**Tyler (Home Manager):**\n';
if (tylerTasks.length === 0) md += 'No tasks due today.\n\n';
else {
  for (const t of tylerTasks) md += '- [ ] ' + t.name + ' \u2014 [ClickUp](https://app.clickup.com/t/' + t.taskId + ')\n';
  md += '\n';
}

md += '**Others \u2014 Due Within 3 Days:**\n';
if (othersTasks.length === 0) md += 'None\n\n';
else {
  for (const t of othersTasks) md += '- [ ] ' + t.name + ' \u2014 assigned to ' + (t.assignees || []).join(', ') + ' \u2014 due ' + t.dueDateFormatted + ' \u2014 [ClickUp](https://app.clickup.com/t/' + t.taskId + ')\n';
  md += '\n';
}

// --- Compute deterministic metrics ---
const now = Date.now() / 1000;
const oldThreshold = 48 * 3600;
const oldEmails = nr.filter(e => e.receivedAt && (now - e.receivedAt) > oldThreshold);

return [{
  json: {
    date: dateStr,
    dateFormatted: dateFmt,
    dayOfWeek,
    briefMarkdown: md,
    metrics: {
      meetingCount: dedupedMeetings.length,
      meetingHours,
      freeHours,
      largestFreeBlockMin: maxGapMin,
      totalTaskCount: overdue.length + dueToday.length + upcoming.length,
      totalEmailCount: nr.length + td.length + pm.length,
      overdueTaskCount: overdue.length,
      needsReplyCount: nr.length,
      oldEmailCount: oldEmails.length,
      weeklyGoalPct: weeklyGoals ? weeklyGoals.completionPct : 0,
      newsBriefLink: newsDoc?.url || '',
      notificationBriefLink: notifDoc?.url || ''
    }
  }
}];

// Combine deterministic brief with AI assessment
const assembly = $('Deterministic Assembly').first().json;
const assessment = $input.first().json.output || $input.first().json.text || '';

// Replace placeholder with AI assessment
const finalBrief = assembly.briefMarkdown.replace(
  '{{COS_ASSESSMENT}}',
  '## COS Assessment\n\n' + assessment + '\n\n---'
);

return [{
  json: {
    date: assembly.date,
    dateFormatted: assembly.dateFormatted,
    dayOfWeek: assembly.dayOfWeek,
    briefMarkdown: finalBrief,
    metrics: assembly.metrics
  }
}];

const brief = $json.briefMarkdown;
const maxLen = 3500;
const truncated = brief.length > maxLen
  ? brief.substring(0, maxLen) + '\n\n_... truncated. See full brief in ClickUp or Google Drive._'
  : brief;

return [{ json: { ...JSON.parse(JSON.stringify($json)), slackBrief: truncated } }];

