// Collect URLs from created artifacts for downstream notifications
const metadata = $('Build Metadata').first().json;
const cuTask = $('Create a task').first().json;
const gdriveDoc = $('Create file from text').first().json;

const clickupUrl = cuTask.url || ('https://app.clickup.com/t/' + (cuTask.id || ''));
const gdriveUrl = gdriveDoc.webViewLink || gdriveDoc.alternateLink || '';

return [{
  json: {
    ...metadata,
    clickupUrl,
    gdriveUrl
  }
}];
